Overall, effective fields behaviour falls into one of three scenarios:

> **Note:**&#x20;
>
> We recommend enabling effective fields as a best practice.

```json&#xA;&#x20;&#x20;:copyable:&#x20;true
  {
  "replicationSpecs": [
    {
      "regionConfigs": [
        {
          "analyticsAutoScaling": {
            "compute": {
              "maxInstanceSize": "M30",
              "minInstanceSize": "M10",
              "enabled": true,
              "scaleDownEnabled": true
            },
            "diskGB": {
              "enabled": true
            }
          },
          "autoScaling": {
            "compute": {
              "maxInstanceSize": "M30",
              "minInstanceSize": "M10",
              "enabled": true,
              "scaleDownEnabled": true
            },
            "diskGB": {
              "enabled": true
            }
          },
          "effectiveAnalyticsSpecs": {
            "instanceSize": "M30",
            "diskIOPS": 3000,
            "diskSizeGB": 100.0,
            "ebsVolumeType": "STANDARD",
            "nodeCount": 0
          },
          "effectiveElectableSpecs": {
            "instanceSize": "M30",
            "diskIOPS": 3000,
            "diskSizeGB": 100.0,
            "ebsVolumeType": "STANDARD",
            "nodeCount": 3
          },
          "effectiveReadOnlySpecs": {
            "instanceSize": "M30",
            "diskIOPS": 3000,
            "diskSizeGB": 100.0,
            "ebsVolumeType": "STANDARD",
            "nodeCount": 0
          },
          "electableSpecs": {
            "instanceSize": "M20",
            "diskSizeGB": 50.0,
            "nodeCount": 3
          },
          "priority": 7,
          "providerName": "AWS",
          "regionName": "US_EAST_1"
        }
      ],
      "zoneId": "6924a70c67695449ba5625ce",
      "zoneName": "Zone 1"
    }
  ]
}
```

